const queries = [
  'longevity OR anti-aging OR aging research OR healthspan OR lifespan',
  'NAD+ OR NMN OR rapamycin OR senolytics OR metformin OR resveratrol',
  'intermittent fasting OR cold exposure OR sauna health OR biological age OR epigenetic clock OR telomere'
];

return queries.map((q, idx) => {
  const prompt = 'You are a content scout for a health and longevity media brand. Find the MOST ENGAGED posts from the LAST 8 HOURS about:\n\n' + q + '\n\nPrioritize posts with HIGH REPLY COUNTS. Skip promotional spam and low-effort posts.\n\nFor each post found, return data in this EXACT JSON array format (no markdown, no code fences, ONLY the JSON array):\n[\n  {\n    "author_name": "Display name",\n    "author_handle": "@handle",\n    "author_follower_count": 0,\n    "full_text": "Full text of the post",\n    "tweet_url": "actual URL from search results",\n    "posted_at_iso": "ISO date",\n    "like_count": 0,\n    "repost_count": 0,\n    "reply_count": 0,\n    "view_count": 0,\n    "is_quote_tweet": false,\n    "quoted_text": "",\n    "discussion_summary": "Brief note on what people seem to be discussing"\n  }\n]\n\nReturn ONLY the JSON array, nothing else.';

  const bodyJson = {
    model: 'grok-4-1-fast',
    input: [
      { role: 'user', content: prompt }
    ],
    tools: [
      { type: 'x_search' }
    ]
  };

  return {
    json: {
      batchIndex: idx,
      bodyJson: JSON.stringify(bodyJson)
    }
  };
});

const uniqueTweets = new Map();

for (const item of $input.all()) {
  let raw = '';

  // xAI Responses API format: output is an array of blocks
  const output = item.json.output;
  if (Array.isArray(output)) {
    for (const block of output) {
      // message type blocks contain content array
      if (block.type === 'message' && Array.isArray(block.content)) {
        for (const c of block.content) {
          if (c.text) raw += c.text;
        }
      }
    }
  }
  // fallback paths
  if (!raw && typeof item.json.output === 'string') {
    raw = item.json.output;
  }
  if (!raw) {
    raw = item.json.output_text || '';
  }

  const cleaned = raw.replace(/```json|```/g, '').trim();

  // Try to extract JSON array even if wrapped in text
  let jsonStr = cleaned;
  const arrMatch = cleaned.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (arrMatch) jsonStr = arrMatch[0];

  try {
    const tweets = JSON.parse(jsonStr);
    if (!Array.isArray(tweets)) continue;
    for (const t of tweets) {
      const key = t.tweet_url || t.full_text;
      if (!key || uniqueTweets.has(key)) continue;
      t.source_pipeline = 'hot_topic';
      t.fetched_at = new Date().toISOString();
      t.like_count = Number(t.like_count) || 0;
      t.repost_count = Number(t.repost_count) || 0;
      t.reply_count = Number(t.reply_count) || 0;
      t.view_count = Number(t.view_count) || 0;
      t.author_follower_count = Number(t.author_follower_count) || 10000;
      uniqueTweets.set(key, t);
    }
  } catch (e) {
    console.error('Parse failed:', e.message);
    console.error('Raw preview:', raw.substring(0, 300));
  }
}

const results = Array.from(uniqueTweets.values());
if (results.length === 0) {
  return [{ json: { _empty: true, message: 'No posts found this round' } }];
}
return results.map(t => ({ json: t }));

const items = $input.all();

const kolHandles = new Set([
  '@Mangan150', '@EricTopol', '@davidasinclair', '@bryan_johnson',
  '@BuckInstitute', '@DrKristieLeong', '@DrMorganLevine', '@HarvardHealth',
  '@foundmyfitness', '@NirBarzilaiMD', '@DrBStanfield', '@CharlesMBrenner',
  '@mkaeberlein', '@aubreydegrey'
]);

const scored = [];
for (const item of items) {
  const t = item.json;
  if (t._empty) continue;
  if (kolHandles.has(t.author_handle)) continue;
  if ((t.reply_count || 0) < 5) continue;
  if ((t.like_count || 0) < 20) continue;
  const replyRatio = t.reply_count / Math.max(t.like_count, 1);
  if (replyRatio < 0.03) continue;
  t.engagement_score = Math.round(t.reply_count * 5 + t.repost_count * 2 + t.like_count * 0.5);
  t.reply_ratio = Math.round(replyRatio * 100) / 100;
  scored.push(t);
}

scored.sort((a, b) => b.engagement_score - a.engagement_score);
const top5 = scored.slice(0, 5);

if (top5.length === 0) {
  return [];
}

return top5.map((t, i) => {
  t.rank = i + 1;
  return { json: t };
});

const items = $input.all();
const results = [];

for (const item of items) {
  const t = item.json;
  if (t._empty) continue;
  const prompt = '你是某个抗衰资讯的中文内容编辑。你精通X的社媒运营，也精通专业的抗衰知识。下面给你一条来自 X 的英文健康/生命科学领域热门推文。请输出严格 JSON：\n\n{\n  "translation_cn": "信达雅的中文翻译，保留专业术语",\n  "longevity_angle": "如果不直接关于长寿，用一句话(20字内)说可以从什么长寿视角切入；如果本身就是长寿话题，写核心赛道",\n  "hook_tip": "一句话(25字内)：这条值得一个做长寿媒体的账号运营者去蹭评论的核心理由 + 建议的回复内容方向（比如质疑/补数据/有趣类比），最好加一推特原生真人用户的回复实例",\n  "comment_vibe": "根据互动数据推测评论区氛围（争议激烈/一边倒支持/质疑声多/科普讨论为主），15字内"\n}\n\n推文作者: ' + t.author_name + ' (@' + t.author_handle + ')\n推文内容: ' + t.full_text + '\n互动: ❤️' + t.like_count + ' 🔁' + t.repost_count + ' 💬' + t.reply_count + '\n' + (t.discussion_summary ? '讨论摘要: ' + t.discussion_summary : '') + '\n\n只返回 JSON，不要任何解释或 markdown。';
  results.push({
    json: {
      prompt: prompt,
      orig_rank: t.rank || 0,
      orig_author_name: '' + (t.author_name || ''),
      orig_author_handle: '' + (t.author_handle || ''),
      orig_full_text: '' + (t.full_text || ''),
      orig_tweet_url: '' + (t.tweet_url || ''),
      orig_like_count: t.like_count || 0,
      orig_repost_count: t.repost_count || 0,
      orig_reply_count: t.reply_count || 0,
      orig_view_count: t.view_count || 0,
      orig_engagement_score: t.engagement_score || 0,
      orig_reply_ratio: t.reply_ratio || 0
    }
  });
}

if (results.length === 0) return [{ json: { _empty: true } }];
return results;

