  var ds = { translation_cn: '(翻译失败)', longevity_angle: '-', hook_tip: '-', comment_vibe: '-' };
  try {
    var cleaned = aiRaw.replace(/```json|```/g, '').trim();
    ds = JSON.parse(cleaned);
  } catch (e) {}
  var rank = orig.orig_rank || (i + 1);
  var score = orig.orig_engagement_score || 0;
  var card = {
    msg_type: 'interactive',
    card: {
      config: { wide_screen_mode: true },
      header: { template: 'red', title: { tag: 'plain_text', content: '\ud83d\udd25 热帖 #' + rank + ' | \ud83d\udcac' + orig.orig_reply_count + ' replies | 分数 ' + score } },
      elements: [
        { tag: 'div', fields: [
          { is_short: true, text: { tag: 'lark_md', content: '**\ud83d\udc64 作者**\n' + orig.orig_author_name + '\n@' + orig.orig_author_handle } },
          { is_short: true, text: { tag: 'lark_md', content: '**\ud83d\udcca 互动**\n\u2764\ufe0f ' + orig.orig_like_count + '  \ud83d\udd01 ' + orig.orig_repost_count + '\n\ud83d\udcac ' + orig.orig_reply_count + '  \ud83d\udc41 ' + (orig.orig_view_count || '-') } }
        ]},
        { tag: 'hr' },
