        { tag: 'div', text: { tag: 'lark_md', content: '**\ud83c\udde8\ud83c\uddf3 译文**\n' + ds.translation_cn } },
        { tag: 'hr' },
        { tag: 'div', text: { tag: 'lark_md', content: '\ud83c\udfaf **长寿切入**：' + ds.longevity_angle } },
        { tag: 'div', text: { tag: 'lark_md', content: '\ud83d\udca1 **蹭点提示**：' + ds.hook_tip } },
        { tag: 'div', text: { tag: 'lark_md', content: '\ud83d\udde3\ufe0f **评论区氛围**：' + ds.comment_vibe } },
        { tag: 'action', actions: [{ tag: 'button', text: { tag: 'plain_text', content: '\ud83d\udd17 查看原推' }, type: 'primary', url: orig.orig_tweet_url }] }
      ]
    }
  };
  results.push({ json: { feishuBody: JSON.stringify(card) } });
}

return results;

const items = $input.all();
const results = [];
var top2 = items.slice(0, 2);

for (var j = 0; j < top2.length; j++) {
  var t = top2[j].json;
  if (t._empty) continue;
  var isQuote = t.is_quote_tweet && t.quoted_text;
  var userPrompt = '你是一个长寿与抗衰媒体的资深内容编辑，擅长将抗衰信息用风趣且专业的语言转化为对抗衰感兴趣的普通中文读者能理解和受益的内容，风格简洁、有温度、不说废话，语气像一个懂行的朋友在微信上给你发消息分享见闻。\n\n请将下面这条来自 X 的帖子，转化为一篇适合发布在中文抗衰资讯网站的短讯息。\n\n---\n原帖作者: ' + t.author_name + ' (' + t.author_handle + ')\n原帖内容: ' + t.full_text + '\n' + (isQuote ? '引用的原帖: ' + t.quoted_text + '\n' : '') + '互动数据: \u2764\ufe0f' + t.like_count + ' \ud83d\udd01' + t.repost_count + ' \ud83d\udcac' + t.reply_count + ' \ud83d\udc41' + t.view_count + '\n' + (t.discussion_summary ? '评论区讨论方向: ' + t.discussion_summary + '\n' : '') + '---\n\n请严格输出以下 JSON（不要 markdown、不要代码块、不要任何解释）：\n\n{\n  "title": "中文标题，12-20字，能让关注健康的用户想点进来看",\n  "body_html": "HTML格式正文，200-300字，不要任何小标题（不要h3/h4），就是2-3段自然段落：第一段讲清楚这是什么事（用人话不用术语堆砌），第二段讲这对关注健康的普通人意味着什么（给一个具体的、生活化的启示或行动建议，不要空洞的鼓励），最后一行写：<p><a href=\\"' + (t.tweet_url || '') + '\\" target=\\"_blank\\">查看原帖 \u2192</a> | 来自 ' + t.author_name + '</p>",\n  "excerpt": "50字左右的摘要",\n  "category_slug": "从以下7个中选一个最匹配的: aging-mechanism / intervention / clinical-progress / lifestyle / industry / assessment / people-opinion",\n  "tags": ["3-5个中文标签"],\n  "seo_title": "SEO标题50字以内",\n  "seo_description": "SEO描述80字以内"\n}';
  results.push({
    json: {
      prompt: userPrompt,
      orig_author_name: '' + (t.author_name || ''),
      orig_author_handle: '' + (t.author_handle || ''),
      orig_full_text: '' + (t.full_text || ''),
      orig_tweet_url: '' + (t.tweet_url || ''),
      orig_source_pipeline: 'hot_topic'
    }
  });
}

if (results.length === 0) return [{ json: { _empty: true } }];
return results;

const items = $input.all();
const promptItems = $('取Top2并构建文章Prompt1').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const aiOutput = items[i].json.output || '';
  const orig = promptItems[i] ? promptItems[i].json : {};
  if (orig._empty) continue;
  let article;
  try {
    const cleaned = aiOutput.replace(/```json|```/g, '').trim();
    article = JSON.parse(cleaned);
  } catch (e) {
    results.push({ json: { wp_body: JSON.stringify({ title: '[待修复] ' + (orig.orig_author_name || ''), content: '<p>AI生成失败</p>', excerpt: '', status: 'draft', categories: [21] }), quality_passed: false } });
    continue;
  }
  const issues = [];
  if (!article.title || article.title.length < 8) issues.push('title_too_short');
  if (!article.body_html || article.body_html.length < 100) issues.push('body_too_short');
  const hasBlocking = issues.some(function(x) { return x === 'title_too_short' || x === 'body_too_short'; });
  results.push({ json: { wp_body: JSON.stringify({ title: article.title || orig.orig_author_name + ' 的最新动态', content: article.body_html || '', excerpt: article.excerpt || '', status: hasBlocking ? 'draft' : 'publish', categories: [21] }), quality_passed: !hasBlocking } });
}

return results;
